-- Migration: eval gate for self-mutation commits (WBS 1.4)
--
-- Adds the 'eval_failed' status to pending_commit so the orchestrator can
-- register commits whose test suite failed separately from 'pending' (which
-- now means tests passed but is waiting for human review — only happens when
-- the auto-push itself fails, as tests-pass commits are pushed automatically).
--
-- Safe to run on an existing database; uses ALTER TABLE … DROP CONSTRAINT /
-- ADD CONSTRAINT pattern which is idempotent when wrapped in DO $$.

DO $$
BEGIN
    -- Drop the old check constraint (name generated by Postgres convention)
    IF EXISTS (
        SELECT 1 FROM information_schema.table_constraints
        WHERE table_name = 'pending_commit'
          AND constraint_type = 'CHECK'
          AND constraint_name LIKE '%status%'
    ) THEN
        ALTER TABLE pending_commit DROP CONSTRAINT IF EXISTS pending_commit_status_check;
    END IF;

    -- Add the new, wider constraint
    ALTER TABLE pending_commit
        ADD CONSTRAINT pending_commit_status_check
        CHECK (status IN ('pending', 'approved', 'rejected', 'eval_failed'));
END
$$;

-- Index to make eval_failed queries fast
CREATE INDEX IF NOT EXISTS pending_commit_eval_failed_idx
    ON pending_commit (agent_name, status, created_at DESC)
    WHERE status = 'eval_failed';
